import json

# Get company list and table list
company_data = locals()['var_functions.query_db:22']
list_result = locals()['var_functions.list_db:4']

if isinstance(list_result, str):
    with open(list_result, 'r') as f:
        tables = json.load(f)
else:
    tables = list_result

# Build company map
company_map = {}
for row in company_data:
    symbol = row['Symbol']
    desc = row['Company Description']
    # Extract company name (first part before "specializes" or similar)
    name_parts = desc.split(' specializes')
    if len(name_parts) == 0:
        name = desc
    else:
        name = name_parts[0].strip()
    company_map[symbol] = name

# Create queries for all symbols
symbols = list(company_map.keys())
queries = {}
for symbol in symbols:
    queries[symbol] = f'SELECT AVG("Volume") as avg_volume FROM "{symbol}" WHERE "Date" >= \'2008-01-01\' AND "Date" <= \'2008-12-31\''

print('__RESULT__:')
print(json.dumps({
    'companies': company_map,
    'query_count': len(queries)
}))

